import { style } from '@angular/animations';
import { HttpErrorResponse } from '@angular/common/http';
import {
  Component,
  EventEmitter,
  OnInit,
  Output,
  QueryList,
  ViewChildren,
} from '@angular/core';
import { Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { hide } from '@popperjs/core';
import { DataTableDirective } from 'angular-datatables';
import { Subject } from 'rxjs';
import { permissionsLabels } from 'src/app/shared/models/fmosNewRolePermissions';
import { ApiService } from 'src/app/shared/services/api.service';
import { LocalStoreService } from 'src/app/shared/services/local-store.service';
import { RoleService } from 'src/app/shared/services/role.service';
import { ToastService } from 'src/app/shared/services/toast.service';
import Swal from 'sweetalert2';

@Component({
  selector: 'npr-global-gcc-ac-maintenance',
  templateUrl: './global-gcc-ac-maintenance.component.html',
  styleUrls: ['./global-gcc-ac-maintenance.component.scss'],
})
export class GlobalGccAcMaintenanceComponent implements OnInit {
  udfFata: any;
  accClassData: any;
  UserId: any;
  gldeleteResponse: any;
  accResponse: any;
  dtOptions: DataTables.Settings[] = [];
  dtTrigger1: Subject<any> = new Subject<any>();
  dtTrigger2: Subject<any> = new Subject<any>();
  isLoading: boolean = false;
  isLoading2: boolean = false;
  udfData: any;
  @ViewChildren(DataTableDirective)
  dtElements: QueryList<DataTableDirective>;
  roleCodes = new permissionsLabels();
  permissions: any;
  allowpermissions: any;
  disallowpermissions: any;
  activeTab: string;
  // isDisabled: boolean = false;
  // statusArr: String[] = ['Authorized', 'Unauthorized', 'Open', 'Close'];

  constructor(
    private apiService: ApiService,
    private toastService: ToastService,
    private roleService: RoleService,
    private router: Router,private ls:LocalStoreService
  ) {}

  ngOnInit(): void {
    console.log('Maintenence');
    this.dtOptions[0] = {
      pagingType: 'full_numbers',
      pageLength: 5,
      columnDefs: [{ type: 'date', targets: [4] }],
      order: [[4, 'desc']],
      processing: true,
      lengthMenu: [
        [5, 10, 20, 30,-1],
        [5, 10, 20, 30,"ALL"],
      ],
      retrieve: true,
      
      // columnDefs: [ { type: 'date', 'targets': [5] } ],
      // order: [[5, 'desc']],
    };
    this.dtOptions[1] = {
      pagingType: 'full_numbers',
      pageLength: 5,
      columnDefs: [{ type: 'date', targets: [4] }],
      order: [[4, 'desc']],
      processing: true,
      lengthMenu: [
        [5, 10, 20, 30,-1],
        [5, 10, 20, 30,"ALL"],
      ],
      retrieve: true,
     
      // columnDefs: [ { type: 'date', 'targets': [5] } ],
      // order: [[5, 'desc']],
    };

    this.getUFDData();
    this.getAccdata();
    this.roleService.fetchScreenPermissions('Global Account Restriction');
    this.roleService.screenLabelList.subscribe(
      (message) => (this.roleCodes = message)
    );
    console.log(this.roleCodes);
    this.ls.removeItem('GLOBALACCFLAG');
    this.ls.removeItem('GLOBALGLFLAG');
  }

  displayToConsole(): void {
    this.dtElements.forEach((dtElement: DataTableDirective, index: number) => {
      dtElement.dtInstance.then((dtInstance: any) => {
        console.log(
          `The DataTable ${index} instance ID is: ${
            dtInstance.table().node().id
          }`
        );
      });
    });
  }

  ngOnDestroy(): void {
    this.dtTrigger1.unsubscribe();
    this.dtTrigger2.unsubscribe();
  }

  getUFDData() {
    this.isLoading = true;
    
    const gltype = "GL";
    this.apiService.getGlData(gltype).subscribe(udfdata => {
      // for (let item of udfdata) {
      //   item.approvedStatus = this.statusArr.find((i) =>
      //     i.startsWith(item.approvedStatus)
      //   );
      // }
      this.udfData = udfdata;
      console.log('this.udfData', this.udfData);
      this.permissions = this.udfData.permission;
      if (this.udfData.length == '0') {
        localStorage.removeItem('ALLOWPERMISSIONS');
        localStorage.removeItem('DISALLOWPERMISSIONS');
      }
      this.allowpermissions = this.udfData.filter(
        (allow) => allow.permission === 'Allow'
      );
      console.log(this.allowpermissions);
      this.disallowpermissions = this.udfData.filter(
        (disallow) => disallow.permission === 'Disallow'
      );
      console.log(this.disallowpermissions);
      if (this.allowpermissions.length != '0') {
        // console.log("AllowPermission",this.allowpermissions);
        localStorage.setItem(
          'ALLOWPERMISSIONS',
          JSON.stringify(this.allowpermissions)
        );
      }

      if (this.disallowpermissions.length != '0') {
        // console.log(  this.disallowpermissions,"disallowpermissions",);
        localStorage.setItem(
          'DISALLOWPERMISSIONS',
          JSON.stringify(this.disallowpermissions)
        );
      }
      if(this.allowpermissions.length >0){
       var button =  document.getElementById("newButton");
       button.style.display = "none";
       
      }

      this.isLoading = false;

      this.dtTrigger1.next();
    });
    
  }
  getAccdata() {
    this.isLoading2 = true;
    const actype = "AC";
    this.apiService.getAccData(actype).subscribe(accdata => {
      // for (let item of accdata) {
      //   item.approvedStatus = this.statusArr.find((i) =>
      //     i.startsWith(item.approvedStatus)
      //   );
      // }
      this.accClassData = accdata;
      if (this.accClassData.length == '0') {
        localStorage.removeItem('ALLOWACCCLASS');
        localStorage.removeItem('DISALLOWACCCLASS');
      }
      this.allowpermissions = this.accClassData.filter(
        (allow) => allow.permission === 'Allow'
      );
      // console.log(this.allowpermissions);
      this.disallowpermissions = this.accClassData.filter(
        (disallow) => disallow.permission === 'Disallow'
      );
      // console.log(this.disallowpermissions);
      if (this.allowpermissions.length != '0') {
        // console.log("AllowPermission");
        localStorage.setItem(
          'ALLOWACCCLASS',
          JSON.stringify(this.allowpermissions)
        );
      }
      if (this.disallowpermissions.length != '0') {
        // console.log(  this.disallowpermissions,"disallowpermissions");
        localStorage.setItem(
          'DISALLOWACCCLASS',
          JSON.stringify(this.disallowpermissions)
        );
      }
      if(this.allowpermissions.length >0){
        var button =  document.getElementById("newButton");
        button.style.display = "none";
        console.log("Enable");
        
       }
      this.isLoading2 = false;

      this.dtTrigger2.next();
      // console.log('ACC Data',this.accClassData);
    });
  }
  OndeleteofUserGCC(UserId, globalGlCodeId) {
    Swal.fire({
      //text: 'Unable to process' + 'Error ' + this.responseforfileupload.errorMessage + 'Do you want to Proceed??',
      text:
        'You are trying to Delete the record. ' + ' Do you want to proceed?',
      showCancelButton: true,
      confirmButtonColor: '#3085d6',
      cancelButtonColor: '#d33',
      // confirmButtonText: 'PROCEED.'
      cancelButtonText: 'NO',
      confirmButtonText: 'YES',
      icon: 'info',
    }).then((result) => {
      if (result.isConfirmed === true) {
        
        this.apiService.deleteGlDetailId(globalGlCodeId).subscribe(
          (resp) => {
            if (resp == true) {
              Swal.fire({
                title: 'Record Is Deleted',
                icon: 'success',
              });
              this.router.navigateByUrl(
                '/system-param-maintenance/global-acc-maintenance-summary'
              );
            } else {
              Swal.fire({
                title: 'Failed to Delete User Data!',
                icon: 'error',
              });
            }
          },
          (error) => {
            if (HttpErrorResponse) {
              Swal.fire({
                text: 'Server Error!',
                icon: 'error',
              });
            }
          }
        );
      }
    });
  }
  OndeleteofUserACC(UserId, globalAccClassId) {
    Swal.fire({
      //text: 'Unable to process' + 'Error ' + this.responseforfileupload.errorMessage + 'Do you want to Proceed??',
      text:
        'You are trying to Delete the record. ' + ' Do you want to proceed?',
      showCancelButton: true,
      confirmButtonColor: '#3085d6',
      cancelButtonColor: '#d33',
      // confirmButtonText: 'PROCEED.'
      cancelButtonText: 'NO',
      confirmButtonText: 'YES',
      icon: 'info',
    }).then((result) => {
      if (result.isConfirmed === true) {
        this.apiService.deleteACCuserdata(globalAccClassId).subscribe(
          (resp) => {
            if (resp == true) {
              Swal.fire({
                title: 'Record Is Deleted',
                icon: 'success',
              });
              this.getUFDData();
              this.router.navigateByUrl(
                '/system-param-maintenance/global-acc-maintenance-summary'
              );
            } else {
              Swal.fire({
                title: 'Failed to Delete User Data!',
                icon: 'error',
              });
            }
          },
          (error) => {
            if (HttpErrorResponse) {
              Swal.fire({
                text: 'Server Error!',
                icon: 'error',
              });
            }
          }
        );
      }
    });
  }
  sendingGccDataforEdit(data) {
    console.log(data, 'Data');
    localStorage.setItem('globalgccacsummryData', JSON.stringify(data));
    this.apiService.setGlobalGccSummary({
      approvedEver: data.approvedEver,
      approvedStatus: data.approvedStatus,
      approvedTime: data.approvedTime,
      approverId: data.approverId,
      createdTime: data.createdTime,
      creatorId: data.creatorId,
      globalGlCodeId: data.globalGlCodeId,
      medGlobalGlCodeDetails: data.medGlobalGlCodeDetails,
      permission: data.permission,
      recordStatus: data.recordStatus,
      modNo: data.modNo,
      activeTab: 'home',
    });
    this.router.navigate(['/system-param-maintenance/global-gl-edit']);
  }
  sendingaccDataforEdit(data) {
    localStorage.setItem('globalaccacsummryData', JSON.stringify(data));
    this.apiService.setGlobalAccSummary({
      approvedEver: data.approvedEver,
      approvedStatus: data.approvedStatus,
      approvedTime: data.approvedTime,
      approverId: data.approverId,
      createdTime: data.createdTime,
      creatorId: data.creatorId,
      globalGlCodeId: data.globalGlCodeId,
      medGlobalGlCodeDetails: data.medGlobalGlCodeDetails,
      permission: data.permission,
      recordStatus: data.recordStatus,
      modNo: data.modNo,
      activeTab: 'profile',
    });
    this.router.navigate(['/system-param-maintenance/global-ac-edit']);
  }
}
